// AUTO-GENERATED DRAFT SCREEN: CryptoNodeSyncStatus
import React from 'react';
import { useQuery } from '@tanstack/react-query';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { Button } from '@/components/ui/button';
import { Progress } from '@/components/ui/progress';
import { Switch } from '@/components/ui/switch';
import { Label } from '@/components/ui/label';
import { cn } from '@/lib/utils';

// Placeholder for tRPC client and hooks
// In a real application, this would be generated by tRPC
const trpc = {
  crypto: {
    getNodeSyncStatus: {
      useQuery: () => {
        // Simulate data fetching
        const { data, isLoading, error, refetch } = useQuery({
          queryKey: ['nodeSyncStatus'],
          queryFn: async () => {
            return new Promise((resolve) => {
              setTimeout(() => {
                const randomProgress = Math.floor(Math.random() * 100);
                resolve({
                  blockHeight: 1234567 + randomProgress,
                  syncProgress: randomProgress,
                  connectionStatus: randomProgress > 90 ? 'Connected' : 'Connecting',
                  peers: Math.floor(Math.random() * 10) + 1,
                });
              }, 1000);
            });
          },
          refetchInterval: 5000, // Refresh every 5 seconds
        });
        return { data, isLoading, error, refetch };
      },
    },
  },
};

type NodeSyncStatus = {
  blockHeight: number;
  syncProgress: number;
  connectionStatus: string;
  peers: number;
};

const CryptoNodeSyncStatus: React.FC = () => {
  const { data, isLoading, error, refetch } = trpc.crypto.getNodeSyncStatus.useQuery();
  const [isDarkTheme, setIsDarkTheme] = React.useState(false);

  if (isLoading) {
    return <div className="flex items-center justify-center h-screen">Loading node sync status...</div>;
  }

  if (error) {
    return <div className="flex items-center justify-center h-screen text-red-500">Error: {error.message}</div>;
  }

  const status = data as NodeSyncStatus;

  return (
    <div className={cn("min-h-screen p-8", { "dark": isDarkTheme })}>
      <div className="container mx-auto">
        <Card className="w-full max-w-md mx-auto">
          <CardHeader>
            <CardTitle className="text-2xl font-bold">Crypto: Node Sync Status</CardTitle>
          </CardHeader>
          <CardContent className="space-y-6">
            <div className="flex items-center justify-between">
              <Label htmlFor="dark-mode">Dark Mode</Label>
              <Switch
                id="dark-mode"
                checked={isDarkTheme}
                onCheckedChange={setIsDarkTheme}
                aria-label="Toggle dark mode"
              />
            </div>

            <div>
              <p className="text-lg font-medium">Block Height: {status.blockHeight}</p>
              <p className="text-lg font-medium">Connection Status: {status.connectionStatus}</p>
              <p className="text-lg font-medium">Connected Peers: {status.peers}</p>
            </div>

            <div>
              <Label htmlFor="sync-progress" className="mb-2 block">Sync Progress: {status.syncProgress}%</Label>
              <Progress id="sync-progress" value={status.syncProgress} className="w-full" />
            </div>

            <Button onClick={() => refetch()} className="w-full">
              Refresh Status
            </Button>
          </CardContent>
        </Card>
      </div>
    </div>
  );
};

export default CryptoNodeSyncStatus;
